<style>
	div {
		/* comment before !important */
		color: red /* c1 */ !important;
		/* comment after !important */
		background: blue !important /* c2 */;
		/* comments on both sides */
		margin: 0 /* c3 */ !important /* c4 */;
		/* control: comment in a plain value */
		padding: 0 /* c5 */;
	}
</style>
